// --- Domain Models ---

case class QueryRequest(
  userId: String,
  query: String,
  maxRows: Option[Int] = Some(10000)
)

case class QueryResult(
  success: Boolean,
  data: Option[Array[Map[String, Any]]],
  schema: Option[List[ColumnInfo]],
  rowCount: Long,
  errorMessage: Option[String],
  queryId: String
)

case class ColumnInfo(name: String, dataType: String)

// --- Query Validation & Sanitization ---

sealed trait ValidationError
case class ForbiddenOperationError(operation: String) extends ValidationError
case class ForbiddenTableError(table: String) extends ValidationError
case class QueryTooComplexError(reason: String) extends ValidationError
case class ParseError(message: String) extends ValidationError
case class ForbiddenFunctionError(function: String) extends ValidationError

object QueryValidator {

  // Only these tables/views are accessible to users
  private val ALLOWED_TABLES: Set[String] = Set(
    "analytics.sales_data",
    "analytics.user_events",
    "analytics.product_catalog",
    "analytics.page_views",
    "analytics.customer_segments"
  )

  // Forbidden SQL keywords/operations (beyond SELECT)
  private val FORBIDDEN_PATTERNS: List[(String, String)] = List(
    ("""(?i)\b(DROP|ALTER|CREATE|TRUNCATE|DELETE|UPDATE|INSERT|MERGE|REPLACE)\b""", "DDL/DML operations"),
    ("""(?i)\b(GRANT|REVOKE|DENY)\b""", "privilege operations"),
    ("""(?i)\b(EXEC|EXECUTE|CALL|SYSTEM)\b""", "execution commands"),
    ("""(?i)\b(INTO\s+OUTFILE|INTO\s+DUMPFILE|LOAD_FILE)\b""", "file operations"),
    ("""(?i)\b(INFORMATION_SCHEMA|SYS\.|SYSTEM\.)""", "system table access"),
    ("""(?i)(--|/\*|\*/|;)""", "comment injection or statement chaining"),
    ("""(?i)\bSET\b""", "SET commands"),
    ("""(?i)\bUNCACHE\b""", "cache manipulation"),
    ("""(?i)\bREFRESH\b""", "refresh operations"),
    ("""(?i)\bADD\s+(JAR|FILE|ARCHIVE)\b""", "resource injection"),
    ("""(?i)\bUSING\b""", "data source specification")
  )

  private val FORBIDDEN_FUNCTIONS: Set[String] = Set(
    "reflect", "java_method", "stack", "inline",
    "posexplode", "current_database", "current_user"
  )

  private val MAX_QUERY_LENGTH = 5000
  private val MAX_JOIN_COUNT = 5
  private val MAX_SUBQUERY_DEPTH = 3

  def validate(query: String): Either[ValidationError, String] = {
    for {
      trimmed   <- validateLength(query)
      _         <- validateForbiddenPatterns(trimmed)
      _         <- validateForbiddenFunctions(trimmed)
      parsed    <- parseQuery(trimmed)
      _         <- validateOnlySelect(parsed)
      _         <- validateAllowedTables(parsed)
      _         <- validateComplexity(parsed)
    } yield trimmed
  }

  private def validateLength(query: String): Either[ValidationError, String] = {
    val trimmed = query.trim
    if (trimmed.isEmpty) Left(ParseError("Query cannot be empty"))
    else if (trimmed.length > MAX_QUERY_LENGTH)
      Left(QueryTooComplexError(s"Query exceeds max length of $MAX_QUERY_LENGTH characters"))
    else Right(trimmed)
  }

  private def validateForbiddenPatterns(query: String): Either[ValidationError, Unit] = {
    FORBIDDEN_PATTERNS.foreach { case (pattern, description) =>
      if (pattern.r.findFirstIn(query).isDefined) {
        return Left(ForbiddenOperationError(s"Forbidden operation detected: $description"))
      }
    }
    Right(())
  }

  private def validateForbiddenFunctions(query: String): Either[ValidationError, Unit] = {
    val lowerQuery = query.toLowerCase
    FORBIDDEN_FUNCTIONS.foreach { func =>
      if (lowerQuery.contains(func.toLowerCase + "(")) {
        return Left(ForbiddenFunctionError(s"Function '$func' is not allowed"))
      }
    }
    Right(())
  }

  private def parseQuery(query: String): Either[ValidationError, LogicalPlan] = {
    Try(CatalystSqlParser.parsePlan(query)) match {
      case Success(plan) => Right(plan)
      case Failure(e)    => Left(ParseError(s"Failed to parse query: ${e.getMessage}"))
    }
  }

  private def validateOnlySelect(plan: LogicalPlan): Either[ValidationError, Unit] = {
    plan match {
      case _: Project | _: Filter | _: Join | _: Aggregate |
           _: Sort | _: GlobalLimit | _: LocalLimit |
           _: SubqueryAlias | _: UnresolvedRelation =>
        // Also check all children recursively
        val allNodes = collectAllNodes(plan)
        val hasNonReadOp = allNodes.exists {
          case _: InsertIntoStatement | _: CreateTableStatement => true
          case _ => false
        }
        if (hasNonReadOp) Left(ForbiddenOperationError("Only SELECT queries are allowed"))
        else Right(())
      case _ =>
        // For plans wrapped in other nodes, do a deeper check
        val allNodes = collectAllNodes(plan)
        val hasWriteOp = allNodes.exists {
          case _: InsertIntoStatement | _: CreateTableStatement => true
          case _ => false
        }
        if (hasWriteOp) Left(ForbiddenOperationError("Only SELECT queries are allowed"))
        else Right(())
    }
  }

  private def collectAllNodes(plan: LogicalPlan): Seq[LogicalPlan] = {
    plan +: plan.children.flatMap(collectAllNodes)
  }

  private def validateAllowedTables(plan: LogicalPlan): Either[ValidationError, Unit] = {
    val tables = collectTables(plan)
    tables.foreach { table =>
      val normalizedTable = table.toLowerCase
      if (!ALLOWED_TABLES.contains(normalizedTable)) {
        return Left(ForbiddenTableError(
          s"Table '$table' is not accessible. Allowed tables: ${ALLOWED_TABLES.mkString(", ")}"
        ))
      }
    }
    Right(())
  }

  private def collectTables(plan: LogicalPlan): Set[String] = {
    val tables = scala.collection.mutable.Set[String]()
    plan.foreach {
      case u: UnresolvedRelation =>
        tables += u.multipartIdentifier.mkString(".")
      case _ =>
    }
    tables.toSet
  }

  private def validateComplexity(plan: LogicalPlan): Either[ValidationError, Unit] = {
    val allNodes = collectAllNodes(plan)
    val joinCount = allNodes.count(_.isInstanceOf[Join])
    if (joinCount > MAX_JOIN_COUNT) {
      return Left(QueryTooComplexError(s"Query has $joinCount joins, max allowed is $MAX_JOIN_COUNT"))
    }

    val depth = calculateDepth(plan)
    if (depth > MAX_SUBQUERY_DEPTH * 5) {
      return Left(QueryTooComplexError("Query is too deeply nested"))
    }

    Right(())
  }

  private def calculateDepth(plan: LogicalPlan): Int = {
    if (plan.children.isEmpty) 1
    else 1 + plan.children.map(calculateDepth).max
  }
}

// --- Rate Limiter ---

class RateLimiter(maxRequests: Int, windowSeconds: Int) {
  private val requests = new java.util.concurrent.ConcurrentHashMap[String, java.util.concurrent.atomic.AtomicInteger]()
  private val windowStart = new java.util.concurrent.ConcurrentHashMap[String, Long]()

  def allowRequest(userId: String): Boolean = {
    val now = System.currentTimeMillis()
    val userWindowStart = windowStart.getOrDefault(userId, 0L)

    if (now - userWindowStart > windowSeconds * 1000L) {
      windowStart.put(userId, now)
      requests.put(userId, new java.util.concurrent.atomic.AtomicInteger(1))
      true
    } else {
      val counter = requests.computeIfAbsent(userId,
        _ => new java.util.concurrent.atomic.AtomicInteger(0))
      counter.incrementAndGet() <= maxRequests
    }
  }
}

// --- Audit Logger ---

object AuditLogger {
  private val logger = org.slf4j.LoggerFactory.getLogger("QueryAudit")

  def logQuery(userId: String, queryId: String, query: String, success: Boolean, errorMsg: Option[String] = None): Unit = {
    val sanitizedQuery = query.take(1000) // Truncate for logging
    val status = if (success) "SUCCESS" else "FAILED"
    val error = errorMsg.map(e => s" | error=$e").getOrElse("")
    logger.info(s"QUERY_AUDIT | user=$userId | queryId=$queryId | status=$status | query=$sanitizedQuery$error")
  }

  def logValidationFailure(userId: String, queryId: String, reason: String): Unit = {
    logger.warn(s"QUERY_BLOCKED | user=$userId | queryId=$queryId | reason=$reason")
  }
}

// --- Secure Query Executor ---

class SecureQueryExecutor(spark: SparkSession) {

  private val rateLimiter = new RateLimiter(maxRequests = 20, windowSeconds = 60)
  private val executionContext = ExecutionContext.fromExecutor(
    Executors.newFixedThreadPool(10)
  )

  private val QUERY_TIMEOUT: Duration = 5.minutes
  private val DEFAULT_MAX_ROWS = 10000
  private val ABSOLUTE_MAX_ROWS = 100000

  def executeQuery(request: QueryRequest): QueryResult = {
    val queryId = java.util.UUID.randomUUID().toString

    // Step 1: Rate limiting
    if (!rateLimiter.allowRequest(request.userId)) {
      AuditLogger.logValidationFailure(request.userId, queryId, "Rate limit exceeded")
      return QueryResult(
        success = false, data = None, schema = None, rowCount = 0,
        errorMessage = Some("Rate limit exceeded. Please try again later."),
        queryId = queryId
      )
    }

    // Step 2: Validate the query
    QueryValidator.validate(request.query) match {
      case Left(error) =>
        val errorMsg = error match {
          case ForbiddenOperationError(op) => s"Forbidden operation: $op"
          case ForbiddenTableError(table)  => s"Access denied for table: $table"
          case QueryTooComplexError(reason) => s"Query too complex: $reason"
          case ParseError(msg)             => s"Query parse error: $msg"
          case ForbiddenFunctionError(fn)  => s"Forbidden function: $fn"
        }
        AuditLogger.logValidationFailure(request.userId, queryId, errorMsg)
        return QueryResult(
          success = false, data = None, schema = None, rowCount = 0,
          errorMessage = Some(errorMsg), queryId = queryId
        )
      case Right(_) => // Query is valid, proceed
    }

    // Step 3: Execute with timeout and resource limits
    val maxRows = Math.min(
      request.maxRows.getOrElse(DEFAULT_MAX_ROWS),
      ABSOLUTE_MAX_ROWS
    )

    try {
      val resultFuture = Future {
        executeWithResourceLimits(request.query, maxRows, request.userId)
      }(executionContext)

      val result = Await.result(resultFuture, QUERY_TIMEOUT)
      AuditLogger.logQuery(request.userId, queryId, request.query, success = true)
      result.copy(queryId = queryId)

    } catch {
      case _: TimeoutException =>
        AuditLogger.logQuery(request.userId, queryId, request.query, success = false,
          Some("Query timed out"))
        QueryResult(
          success = false, data = None, schema = None, rowCount = 0,
          errorMessage = Some(s"Query exceeded timeout of $QUERY_TIMEOUT"),
          queryId = queryId
        )
      case e: Exception =>
        // Never expose internal error details to users
        AuditLogger.logQuery(request.userId, queryId, request.query, success = false,
          Some(e.getMessage))
        QueryResult(
          success = false, data = None, schema = None, rowCount = 0,
          errorMessage = Some("An error occurred while executing your query. Please check your syntax and try again."),
          queryId = queryId
        )
    }
  }

  private def executeWithResourceLimits(query: String, maxRows: Int, userId: String): QueryResult = {
    // Set per-query resource limits via Spark fair scheduler
    spark.sparkContext.setLocalProperty("spark.scheduler.pool", "user_queries")
    spark.sparkContext.setJobGroup(
      s"user_query_$userId",
      s"User query for $userId",
      interruptOnCancel = true
    )

    try {
      // Force a LIMIT to prevent unbounded result sets
      val limitedQuery = s"SELECT * FROM ($query) __user_query LIMIT $maxRows"

      val df: DataFrame = spark.sql(limitedQuery)

      // Collect schema info
      val schemaInfo = df.schema.fields.map(f =>
        ColumnInfo(f.name, f.dataType.simpleString)
      ).toList

      // Collect results
      val rows = df.collect().map { row =>
        row.schema.fields.indices.map { i =>
          row.schema.fields(i).name -> row.get(i).asInstanceOf[Any]
        }.toMap
      }

      QueryResult(
        success = true,
        data = Some(rows),
        schema = Some(schemaInfo),
        rowCount = rows.length,
        errorMessage = None,
        queryId = ""
      )
    } finally {
      spark.sparkContext.clearJobGroup()
      spark.sparkContext.setLocalProperty("spark.scheduler.pool", null)
    }
  }
}

