object AnalyticsPlatformApp {

  def main(args: Array[String]): Unit = {
    val spark = SparkSession.builder()
      .appName("Secure Analytics Platform")
      .config("spark.sql.adaptive.enabled", "true")
      // Restrict file-based data source access
      .config("spark.sql.catalog.spark_catalog", "org.apache.spark.sql.hive.HiveCatalog")
      // Disable dangerous features
      .config("spark.sql.runSQLOnFiles", "false")
      .config("spark.hadoop.fs.permissions.umask-mode", "077")
      // Fair scheduler for resource isolation
      .config("spark.scheduler.mode", "FAIR")
      .config("spark.scheduler.allocation.file", "/opt/spark/conf/fairscheduler.xml")
      .enableHiveSupport()
      .getOrCreate()

    // Restrict Spark SQL to only the analytics database
    spark.sql("USE analytics")

    val executor = new SecureQueryExecutor(spark)

    // Register allowed views (materialized for the analytics layer)
    setupAllowedViews(spark)

    // --- Example: Akka HTTP or similar API integration ---
    // In production, integrate with your API framework (Akka HTTP, Play, http4s, etc.)
    //
    // POST /api/v1/query
    // {
    //   "userId": "user123",
    //   "query": "SELECT product_name, SUM(revenue) as total_revenue FROM analytics.sales_data GROUP BY product_name ORDER BY total_revenue DESC",
    //   "maxRows": 1000
    // }

    // Demo execution
    val demoRequest = QueryRequest(
      userId = "demo_user",
      query = "SELECT product_name, SUM(revenue) as total_revenue FROM analytics.sales_data GROUP BY product_name ORDER BY total_revenue DESC",
      maxRows = Some(100)
    )

    val result = executor.executeQuery(demoRequest)
    println(s"Query ${result.queryId}: success=${result.success}, rows=${result.rowCount}")
    result.errorMessage.foreach(e => println(s"Error: $e"))

    // Demonstrate blocked queries
    val maliciousRequests = List(
      QueryRequest("hacker", "DROP TABLE analytics.sales_data", None),
      QueryRequest("hacker", "SELECT * FROM information_schema.tables", None),
      QueryRequest("hacker", "SELECT * FROM secret_database.passwords", None),
      QueryRequest("hacker", "SELECT reflect('java.lang.Runtime', 'exec', 'rm -rf /')", None),
      QueryRequest("hacker", "SELECT 1; DROP TABLE analytics.sales_data", None)
    )

    maliciousRequests.foreach { req =>
      val res = executor.executeQuery(req)
      println(s"Blocked query from ${req.userId}: ${res.errorMessage.getOrElse("N/A")}")
    }

    spark.stop()
  }

  private def setupAllowedViews(spark: SparkSession): Unit = {
    // Create secure views that restrict column-level access if needed
    // These views act as an additional security layer

    // Example: Create a view that masks sensitive columns
    Try {
      spark.sql(
        """
          |CREATE OR REPLACE VIEW analytics.sales_data AS
          |SELECT
          |  order_id,
          |  product_name,
          |  category,
          |  revenue,
          |  quantity,
          |  order_date,
          |  region
          |  -- Deliberately excluding: customer_ssn, customer_email, internal_cost
          |FROM raw_data.sales
        """.stripMargin)
    }
  }
}

// --- HTTP API with Akka HTTP (example integration) ---

import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.http.scaladsl.server.Directives._
import akka.http.scaladsl.marshallers.sprayjson.SprayJsonSupport._
import spray.json._

trait JsonFormats extends DefaultJsonProtocol {
  implicit val columnInfoFormat: RootJsonFormat[ColumnInfo] = jsonFormat2(ColumnInfo)
  implicit val queryRequestFormat: RootJsonFormat[QueryRequest] = jsonFormat3(QueryRequest)

  implicit object AnyJsonFormat extends JsonFormat[Any] {
    def write(x: Any): JsValue = x match {
      case n: Int => JsNumber(n)
      case l: Long => JsNumber(l)
      case d: Double => JsNumber(d)
      case s: String => JsString(s)
      case b: Boolean => if (b) JsTrue else JsFalse
      case null => JsNull
      case other => JsString(other.toString)
    }
    def read(value: JsValue): Any = value match {
      case JsNumber(n) => if (n.isValidInt) n.intValue else n.doubleValue
      case JsString(s) => s
      case JsTrue => true
      case JsFalse => false
      case JsNull => null
      case _ => value.toString
    }
  }

  implicit val queryResultFormat: RootJsonFormat[QueryResult] = jsonFormat6(QueryResult)
}

class AnalyticsHttpApi(executor: SecureQueryExecutor) extends JsonFormats {

  implicit val system: ActorSystem = ActorSystem("analytics-api")

  private def authenticateUser(token: String): Option[String] = {
    // Integrate with your authentication system (OAuth2, JWT, etc.)
    // Returns userId if valid, None otherwise
    // This is a placeholder - NEVER skip authentication
    if (token.nonEmpty && token.startsWith("Bearer ")) {
      Some(s"user_${token.hashCode.abs}")
    } else {
      None
    }
  }

  val routes = {
    pathPrefix("api" / "v1") {
      path("query") {
        post {
          optionalHeaderValueByName("Authorization") { authHeader =>
            authHeader.flatMap(authenticateUser) match {
              case None =>
                complete(StatusCodes.Unauthorized -> """{"error":"Authentication required"}""")
              case Some(userId) =>
                entity(as[QueryRequest]) { request =>
                  // Override userId with authenticated user (don't trust client-supplied userId)
                  val secureRequest = request.copy(userId = userId)
                  val result = executor.executeQuery(secureRequest)
                  val statusCode = if (result.success) StatusCodes.OK else StatusCodes.BadRequest
                  complete(statusCode -> result.toJson.prettyPrint)
                }
            }
          }
        }
      } ~
      path("tables") {
        get {
          // Return list of allowed tables and their schemas
          val tablesInfo = Map(
            "allowed_tables" -> QueryValidator.getClass.getDeclaredFields
              .find(_.getName.contains("ALLOWED_TABLES"))
              .map(_ => List(
                "analytics.sales_data",
                "analytics.user_events",
                "analytics.product_catalog",
                "analytics.page_views",
                "analytics.customer_segments"
              ))
              .getOrElse(List.empty)
          )
          complete(StatusCodes.OK -> tablesInfo.toJson.prettyPrint)
        }
      }
    }
  }

  def start(host: String = "0.0.0.0", port: Int = 8080): Unit = {
    Http().newServerAt(host, port).bind(routes)
    println(s"Analytics API running at http://$host:$port")
  }
}